sql:
SELECT feedback_text
FROM coach_feedback
WHERE user_id = 1;

SELECT badge_name
FROM user_badges
ORDER BY badge_name ASC;

external_knowledge:
- 'Earned badges' refers to users who have acquired certain badges at a specific point in time (earned_at).; 
- 'Received feedback in 2023' means that the feedback was given to users in the year 2023, as indicated by the created_at timestamp.; 
- 'Total feedback counts' represent the number of times each user received feedback.

sql:
SELECT user_id, feedback_text, created_at
FROM coach_feedback
ORDER BY created_at DESC;

SELECT DISTINCT user_id
FROM coach_feedback
WHERE user_id NOT IN (
  SELECT user_id
  FROM user_badges
);
